323	pub enum ArtifactError {
324	    TooLarge(&'static str),
325	    EmptyBundleName,
326	    EmptyTarget,
327	    EmptyPayloadName,
328	    EmptyPayload,
329	    EmptyEntrySymbol,
330	    Truncated(&'static str),
331	    BadMagic,
332	    UnsupportedVersion(u16),
333	    UnsupportedCompileOptions(u64),
334	    MalformedCompileOptions(String),
335	    UnsupportedPayloadKind(u16),
336	    UnsupportedEntryKind(u16),
337	    InvalidUtf8(&'static str),
338	    UnsupportedHostTarget(String),
339	    Object(String),
340	    Malformed(String),
341	}
