343	impl fmt::Display for ArtifactError {
344	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
345	        match self {
346	            Self::TooLarge(field) => write!(f, "embedded artifact {field} is too large"),
347	            Self::EmptyBundleName => f.write_str("embedded artifact bundle name is empty"),
348	            Self::EmptyTarget => f.write_str("embedded artifact target is empty"),
349	            Self::EmptyPayloadName => f.write_str("embedded artifact payload name is empty"),
350	            Self::EmptyPayload => f.write_str("embedded artifact payload is empty"),
351	            Self::EmptyEntrySymbol => f.write_str("embedded artifact entry symbol is empty"),
352	            Self::Truncated(field) => write!(f, "embedded artifact is truncated in {field}"),
353	            Self::BadMagic => f.write_str("embedded artifact has bad magic"),
354	            Self::UnsupportedVersion(version) => {
355	                write!(f, "unsupported embedded artifact version {version}")
356	            }
357	            Self::UnsupportedCompileOptions(bits) => {
358	                write!(
359	                    f,
360	                    "unsupported embedded artifact compile-options bits {bits:#x}"
361	                )
362	            }
363	            Self::MalformedCompileOptions(message) => {
364	                write!(f, "malformed cuda-oxide compile options: {message}")
365	            }
366	            Self::UnsupportedPayloadKind(kind) => {
367	                write!(f, "unsupported embedded artifact payload kind {kind}")
368	            }
369	            Self::UnsupportedEntryKind(kind) => {
370	                write!(f, "unsupported embedded artifact entry kind {kind}")
371	            }
372	            Self::InvalidUtf8(field) => write!(f, "embedded artifact {field} is not utf-8"),
373	            Self::UnsupportedHostTarget(target) => {
374	                write!(f, "unsupported host object target '{target}'")
375	            }
376	            Self::Object(message) | Self::Malformed(message) => f.write_str(message),
377	        }
378	    }
379	}
