605	pub fn read_artifact_bundles_from_object_bytes(
606	    bytes: &[u8],
607	) -> Result<Vec<OwnedArtifactBundle>, ArtifactError> {
608	    use object::{Object, ObjectSection};
609	
610	    let file = object::File::parse(bytes).map_err(|e| ArtifactError::Object(e.to_string()))?;
611	    let mut bundles = Vec::new();
612	    for section in file.sections() {
613	        let name = section
614	            .name()
615	            .map_err(|e| ArtifactError::Object(e.to_string()))?;
616	        if name != ARTIFACT_SECTION_NAME {
617	            continue;
618	        }
619	        let data = section
620	            .data()
621	            .map_err(|e| ArtifactError::Object(e.to_string()))?;
622	        bundles.extend(parse_artifact_section(data)?.into_iter().map(Into::into));
623	    }
624	    Ok(bundles)
625	}
