757	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
758	struct HostObjectTarget {
759	    format: object::BinaryFormat,
760	    architecture: object::Architecture,
761	    endianness: object::Endianness,
762	}
763	
764	#[cfg(feature = "object-write")]
765	impl HostObjectTarget {
766	    fn parse(target: &str) -> Result<Self, ArtifactError> {
767	        let target = target.to_ascii_lowercase();
768	        let (architecture, endianness) = if target.starts_with("x86_64")
769	            || target.starts_with("amd64")
770	            || target.starts_with("x86-64")
771	        {
772	            (object::Architecture::X86_64, object::Endianness::Little)
773	        } else if target.starts_with("aarch64") || target.starts_with("arm64") {
774	            (object::Architecture::Aarch64, object::Endianness::Little)
775	        } else {
776	            return Err(ArtifactError::UnsupportedHostTarget(target));
777	        };
778	
779	        let format = if target.contains("linux") {
780	            object::BinaryFormat::Elf
781	        } else {
782	            return Err(ArtifactError::UnsupportedHostTarget(target));
783	        };
784	
785	        Ok(Self {
786	            format,
787	            architecture,
788	            endianness,
789	        })
790	    }
791	}
